/**
 * @summary Listo qytetet
 */
export const getListCitiesUrl = (params?: ListCitiesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/locations/cities?${stringifiedParams}`
    : `/api/locations/cities`;
};

export const listCities = async (
  params?: ListCitiesParams,
  options?: RequestInit,
): Promise<string[]> => {
  return customFetch<string[]>(getListCitiesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListCitiesQueryKey = (params?: ListCitiesParams) => {
  return [`/api/locations/cities`, ...(params ? [params] : [])] as const;
};

